import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Plus, Calendar, Trash2, 
  PieChart, Wallet, X, Save, AlertTriangle 
} from 'lucide-react';

const Cartoes = () => {
  const [cartoes, setCartoes] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(true);
  const [novoCartao, setNovoCartao] = useState({
    nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#4361ee'
  });

  const colors = {
    primary: '#4361ee',
    success: '#4caf50',
    danger: '#f72585',
    warning: '#ff9800'
  };

  useEffect(() => {
    fetchCartoesEStatus();
  }, []);

  async function fetchCartoesEStatus() {
    setLoading(true);
    // 1. Busca os cartões
    const { data: listaCartoes } = await supabase.from('cartoes').select('*');
    
    // 2. Busca as compras para calcular o gasto atual (Simulação de lógica)
    // Aqui você somaria os gastos do mês atual vinculados ao nome do cartão
    const { data: compras } = await supabase.from('compras').select('valor_total, cartao');

    const cartoesComGasto = listaCartoes?.map(c => {
      const gastoTotal = compras
        ?.filter(compra => compra.cartao === c.nome)
        .reduce((acc, curr) => acc + parseFloat(curr.valor_total), 0) || 0;
      return { ...c, gastoAtual: gastoTotal };
    });

    setCartoes(cartoesComGasto || []);
    setLoading(false);
  }

  async function salvarCartao() {
    const { error } = await supabase.from('cartoes').insert([novoCartao]);
    if (!error) {
      setShowModal(false);
      fetchCartoesEStatus();
      setNovoCartao({ nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#4361ee' });
    }
  }

  const formatMoney = (v) => `R$ ${parseFloat(v).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in" style={{ padding: '20px', backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      
      {/* HEADER */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <div>
          <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: '#333', margin: 0 }}>
            <CreditCard size={28} color={colors.primary} /> Meus Cartões
          </h2>
          <p style={{ color: '#636e72', margin: '5px 0 0 0' }}>Gerenciamento de limites e ciclos de fatura</p>
        </div>
        <button onClick={() => setShowModal(true)} style={btnNovoStyle(colors.primary)}>
          <Plus size={20} /> Adicionar Cartão
        </button>
      </div>

      {/* GRID */}
      <div style={gridStyle}>
        {cartoes.map((cartao) => {
          const porcentagemUso = (cartao.gastoAtual / cartao.limite) * 100;
          const disponivel = cartao.limite - cartao.gastoAtual;

          return (
            <div key={cartao.id} style={cartaoEstilizado(cartao.cor)}>
              <div style={cardGlassEffect}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <span style={{ fontWeight: 800, fontSize: '1.2rem' }}>{cartao.nome}</span>
                  <div style={chipStyle} />
                </div>

                <div style={{ marginTop: '20px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.75rem', opacity: 0.9 }}>
                    <span>LIMITE DISPONÍVEL</span>
                    <span>{porcentagemUso.toFixed(0)}% USADO</span>
                  </div>
                  <div style={{ fontSize: '1.5rem', fontWeight: 800 }}>{formatMoney(disponivel)}</div>
                  
                  {/* BARRA DE PROGRESSO */}
                  <div style={progressBg}>
                    <div style={progressFill(porcentagemUso)} />
                  </div>
                </div>

                <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '20px' }}>
                  <div style={infoBox}>
                    <Calendar size={12} />
                    <span>Vence dia: <strong>{cartao.dia_vencimento}</strong></span>
                  </div>
                  <div style={infoBox}>
                    <AlertTriangle size={12} />
                    <span>Fecha dia: <strong>{cartao.dia_fechamento}</strong></span>
                  </div>
                </div>
              </div>
              
              <div style={cartaoFooterStyle}>
                <span style={{ fontSize: '0.7rem', opacity: 0.8 }}>Limite Total: {formatMoney(cartao.limite)}</span>
                <button style={{ background: 'none', border: 'none', color: '#ff4d4d', cursor: 'pointer' }}>
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* MODAL DE CADASTRO */}
      {showModal && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3>Novo Cartão</h3>
              <X onClick={() => setShowModal(false)} style={{ cursor: 'pointer' }} />
            </div>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
              <input 
                placeholder="Nome do Banco/Cartão" 
                style={inputStyle} 
                onChange={e => setNovoCartao({...novoCartao, nome: e.target.value})}
              />
              <input 
                placeholder="Limite Total (R$)" 
                type="number" 
                style={inputStyle}
                onChange={e => setNovoCartao({...novoCartao, limite: e.target.value})}
              />
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                <input 
                  placeholder="Dia Fechamento" 
                  type="number" 
                  style={inputStyle}
                  onChange={e => setNovoCartao({...novoCartao, dia_fechamento: e.target.value})}
                />
                <input 
                  placeholder="Dia Vencimento" 
                  type="number" 
                  style={inputStyle}
                  onChange={e => setNovoCartao({...novoCartao, dia_vencimento: e.target.value})}
                />
              </div>
              <input 
                type="color" 
                style={{ width: '100%', height: '40px', border: 'none', cursor: 'pointer' }}
                value={novoCartao.cor}
                onChange={e => setNovoCartao({...novoCartao, cor: e.target.value})}
              />
              <button onClick={salvarCartao} style={btnSalvarStyle}>
                <Save size={18} /> Salvar Cartão
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

